INSERT INTO public.questions VALUES ('7450e79e-25c9-4985-a911-b499472f7384', 'true_false', '图书馆目录查询系统（OPAC）就是一种人工智能系统，和ChatGPT的原理完全相同。（　　）', '{"F": "错误", "T": "正确"}', 'F', 'OPAC基于倒排索引和规则匹配进行关键词检索，与大语言模型的概率生成原理截然不同。', NULL, 3, NULL, 'null', NULL, NULL, NULL, 'draft', 0, NULL, NULL, NULL, NULL, 'f153e781-dca0-46af-8430-a62aa9b59a9b', NULL, '2026-04-14 02:25:06.817106+00', '2026-04-14 02:25:06.81711+00');
INSERT INTO public.questions VALUES ('527f2721-6050-43ef-9848-60b9213022ef', 'true_false', 'ChatGPT等AI聊天工具回答读者咨询时，始终能实时联网查到最新资料。（　　）', '{"F": "错误", "T": "正确"}', 'F', '大多数AI聊天工具基于固定训练数据，默认不联网；即使有联网版本，实时性和准确性也有限，无法保证始终获取最新资料。', NULL, 3, NULL, 'null', NULL, NULL, NULL, 'draft', 0, NULL, NULL, NULL, NULL, 'f153e781-dca0-46af-8430-a62aa9b59a9b', NULL, '2026-04-14 02:25:06.822888+00', '2026-04-14 02:25:06.822893+00');
INSERT INTO public.questions VALUES ('c007a69b-99ab-430f-bf76-107c973ce380', 'true_false', '图书馆员工可以直接将含有读者借阅记录的数据文件上传到免费AI工具中进行数据分析，不存在任何隐私风险。（　　）', '{"F": "错误", "T": "正确"}', 'F', '含有读者个人信息的数据上传至免费第三方AI工具，存在数据泄露、违反隐私法规和职业伦理的风险，应严格禁止。', NULL, 3, NULL, 'null', NULL, NULL, NULL, 'draft', 0, NULL, NULL, NULL, NULL, 'f153e781-dca0-46af-8430-a62aa9b59a9b', NULL, '2026-04-14 02:25:06.828102+00', '2026-04-14 02:25:06.828111+00');
INSERT INTO public.questions VALUES ('73273559-a3cb-467b-849a-4e3a245da131', 'true_false', 'AI工具可以帮助馆员为书目记录自动生成主题词建议，但最终结果需要人工审核。（　　）', '{"F": "错误", "T": "正确"}', 'T', 'AI辅助主题词生成是合理的技术辅助手段，但涉及专业判断，必须经专业馆员审核才可采用。', NULL, 3, NULL, 'null', NULL, NULL, NULL, 'draft', 0, NULL, NULL, NULL, NULL, 'f153e781-dca0-46af-8430-a62aa9b59a9b', NULL, '2026-04-14 02:25:06.833088+00', '2026-04-14 02:25:06.833093+00');
INSERT INTO public.questions VALUES ('e1c174d7-8c74-4bd2-bbfc-1850fc45bf25', 'true_false', '读者在使用AI帮助查找文献时，AI给出的文献引用格式和来源信息一定是准确的。（　　）', '{"F": "错误", "T": "正确"}', 'F', 'AI幻觉问题普遍存在，AI给出的文献引用极可能是虚构的，必须通过数据库逐一核实。', NULL, 3, NULL, 'null', NULL, NULL, NULL, 'draft', 0, NULL, NULL, NULL, NULL, 'f153e781-dca0-46af-8430-a62aa9b59a9b', NULL, '2026-04-14 02:25:06.837007+00', '2026-04-14 02:25:06.837012+00');
INSERT INTO public.questions VALUES ('b59b450c-83a1-4406-9540-ed36dfcfa61b', 'true_false', '大语言模型（如ChatGPT）生成答案的方式，类似于它在互联网上对每个问题进行一次实时搜索后再作答。（　　）', '{"F": "错误", "T": "正确"}', 'F', 'LLM的核心机制是基于训练语料预测下一个词，与实时搜索根本不同；联网功能是额外模块，非基本原理。', NULL, 3, NULL, 'null', NULL, NULL, NULL, 'draft', 0, NULL, NULL, NULL, NULL, 'f153e781-dca0-46af-8430-a62aa9b59a9b', NULL, '2026-04-14 02:25:06.841076+00', '2026-04-14 02:25:06.841084+00');
INSERT INTO public.questions VALUES ('1a97e453-9372-4317-975d-f035ce13f9e7', 'true_false', 'AI可以辅助图书馆员完成常规的、重复性文本处理工作，如摘要生成、分类建议等。（　　）', '{"F": "错误", "T": "正确"}', 'T', '摘要生成、文档分类、格式转换等重复性文本处理正是当前AI工具的优势场景，可显著提升馆员工作效率。', NULL, 3, NULL, 'null', NULL, NULL, NULL, 'draft', 0, NULL, NULL, NULL, NULL, 'f153e781-dca0-46af-8430-a62aa9b59a9b', NULL, '2026-04-14 02:25:06.844989+00', '2026-04-14 02:25:06.844994+00');
INSERT INTO public.questions VALUES ('71b8bcef-4dfb-4868-beb1-42ea3dece170', 'true_false', '经AI工具翻译的外文资源介绍或馆藏导读，无需人工校对就可以直接发布给读者。（　　）', '{"F": "错误", "T": "正确"}', 'F', '机器翻译存在错译、漏译、专有名词误译等风险，图书馆面向读者发布的内容必须经过人工校对。', NULL, 3, NULL, 'null', NULL, NULL, NULL, 'draft', 0, NULL, NULL, NULL, NULL, 'f153e781-dca0-46af-8430-a62aa9b59a9b', NULL, '2026-04-14 02:25:06.849122+00', '2026-04-14 02:25:06.849129+00');
INSERT INTO public.questions VALUES ('533c1a52-70fd-4431-a503-1c09a5d26e39', 'true_false', '【AI幻觉】是指AI会随机生成听起来正确但实际上可能是错误的信息。（　　）', '{"F": "错误", "T": "正确"}', 'T', 'AI幻觉即模型生成了统计上【合理】但实际上错误的内容，这是概率生成机制的固有缺陷，非故意欺骗。', NULL, 3, NULL, 'null', NULL, NULL, NULL, 'draft', 0, NULL, NULL, NULL, NULL, 'f153e781-dca0-46af-8430-a62aa9b59a9b', NULL, '2026-04-14 02:25:06.853217+00', '2026-04-14 02:25:06.853222+00');
INSERT INTO public.questions VALUES ('c23f7a68-362c-409d-8254-f1fb62800b07', 'true_false', '图书馆员具备一定的AI素养，能够帮助读者更好地辨别AI生成内容的可信度，这是信息素养教育的延伸。（　　）', '{"F": "错误", "T": "正确"}', 'T', '信息素养教育在AI时代延伸为AI素养教育，图书馆员帮助读者批判性识别AI内容是专业职责的自然延展。', NULL, 3, NULL, 'null', NULL, NULL, NULL, 'draft', 0, NULL, NULL, NULL, NULL, 'f153e781-dca0-46af-8430-a62aa9b59a9b', NULL, '2026-04-14 02:25:06.85717+00', '2026-04-14 02:25:06.857174+00');
INSERT INTO public.questions VALUES ('956ff3cd-9198-492b-b9dd-aa9daaf097f3', 'true_false', '对比学习（Contrastive Learning）是训练嵌入模型的核心技术之一，在构建语义检索系统时，选择嵌入模型的质量直接影响最终检索效果，远比向量数据库的选型更为关键。（　　）', '{"F": "错误", "T": "正确"}', 'T', '嵌入模型质量决定语义向量空间的表征能力，是语义检索系统的核心；向量数据库主要负责存储和检索，是基础设施层，相对标准化。', NULL, 3, NULL, 'null', NULL, NULL, NULL, 'draft', 0, NULL, NULL, NULL, NULL, 'f153e781-dca0-46af-8430-a62aa9b59a9b', NULL, '2026-04-14 02:28:11.178974+00', '2026-04-14 02:28:11.17898+00');
INSERT INTO public.questions VALUES ('b43cc4f4-673c-4f95-8dd2-9ed430f33a02', 'single_choice', '以下哪种说法最准确地描述了AI聊天工具（如文心一言、ChatGPT）的工作方式？（　　）', '{"A": "它在图书馆数据库里检索最相关的答案后返回给用户", "B": "它基于大量文本训练，通过预测下一个最可能出现的词来生成回复", "C": "它将用户问题发送给专家团队，由人工回答后再返回", "D": "它读取互联网上所有网页的实时内容后综合作答"}', 'B', 'LLM的核心是基于大规模语料统计规律进行下一词预测，而非实时检索或人工回答。', NULL, 3, NULL, 'null', NULL, NULL, NULL, 'draft', 0, NULL, NULL, NULL, NULL, 'f153e781-dca0-46af-8430-a62aa9b59a9b', NULL, '2026-04-14 02:25:06.861925+00', '2026-04-14 02:25:06.86193+00');
INSERT INTO public.questions VALUES ('fe137404-a2b9-4286-8f62-a6167667e256', 'single_choice', '一位读者来到咨询台，说AI给他推荐了一篇论文，但他在中国知网、万方等数据库中怎么都找不到。最可能的原因是什么？（　　）', '{"A": "该论文被数据库删除了", "B": "AI发生了【幻觉】，编造了一篇并不存在的论文", "C": "读者的数据库检索方式有误", "D": "该论文存在于境外数据库，国内无法访问"}', 'B', 'AI幻觉的典型表现就是编造看似真实的不存在的文献，文献检索中属于高风险情形。', NULL, 3, NULL, 'null', NULL, NULL, NULL, 'draft', 0, NULL, NULL, NULL, NULL, 'f153e781-dca0-46af-8430-a62aa9b59a9b', NULL, '2026-04-14 02:25:06.866394+00', '2026-04-14 02:25:06.866399+00');
INSERT INTO public.questions VALUES ('9f37e00e-ebf2-46fa-bc3f-5c64572453b0', 'single_choice', '图书馆正在考虑用AI辅助工具帮助读者推荐馆藏图书。以下哪个风险最需要提前关注？（　　）', '{"A": "AI推荐速度太慢，影响用户体验", "B": "AI可能因训练数据偏差，导致推荐结果对某类读者群体不公平", "C": "AI无法理解图书的书名", "D": "AI推荐的图书馆里一定没有"}', 'B', '训练数据偏差会导致推荐偏向特定人群，公平性是AI应用中的首要伦理风险。', NULL, 3, NULL, 'null', NULL, NULL, NULL, 'draft', 0, NULL, NULL, NULL, NULL, 'f153e781-dca0-46af-8430-a62aa9b59a9b', NULL, '2026-04-14 02:25:06.869578+00', '2026-04-14 02:25:06.869581+00');
INSERT INTO public.questions VALUES ('037a4ad4-84f7-4700-95ab-aa24d909ad3c', 'single_choice', '馆员小李用AI工具帮忙写了一份读者活动的宣传文案。以下哪种做法最为规范？（　　）', '{"A": "直接发布，AI写的内容肯定没有错误", "B": "发布前仔细核对内容的事实准确性，修改不当表述后再发布", "C": "标注【本文由AI全权撰写】后直接发布", "D": "不用AI，全部手写才最安全"}', 'B', 'AI生成的文案可能包含事实错误或不当表述，发布前必须人工审核，这是馆员职业责任的基本要求。', NULL, 3, NULL, 'null', NULL, NULL, NULL, 'draft', 0, NULL, NULL, NULL, NULL, 'f153e781-dca0-46af-8430-a62aa9b59a9b', NULL, '2026-04-14 02:25:06.873347+00', '2026-04-14 02:25:06.873352+00');
INSERT INTO public.questions VALUES ('5c591f5b-2f03-4f68-96b0-3e15ee5fceb2', 'single_choice', '以下哪个场景中，AI工具对图书馆工作的辅助效果最为直接有效？（　　）', '{"A": "代替馆员向读者提供情感关怀和人文陪伴", "B": "自动完成对馆藏资源的真实性和学术价值的鉴定", "C": "批量翻译外文图书摘要，供馆员参考使用", "D": "完全替代馆员完成参考咨询工作"}', 'C', '批量翻译外文摘要是AI的优势场景，可大幅节省人力；但翻译结果仍需馆员参考核用，非完全替代。', NULL, 3, NULL, 'null', NULL, NULL, NULL, 'draft', 0, NULL, NULL, NULL, NULL, 'f153e781-dca0-46af-8430-a62aa9b59a9b', NULL, '2026-04-14 02:25:06.876398+00', '2026-04-14 02:25:06.876402+00');
INSERT INTO public.questions VALUES ('27c562fb-ed61-459b-940a-d59d10eba8b2', 'single_choice', '读者问：图书馆为什么要我们了解AI？最合适的回应是（　　）：', '{"A": "AI和图书馆关系不大，我们主要做好借还书服务就好", "B": "AI正在改变信息获取方式，图书馆员需要了解AI的能力与局限，才能帮助读者更好地识别和利用信息", "C": "AI会替代图书馆员，所以我们不需要学了", "D": "只有技术部门的馆员才需要学AI"}', 'B', 'AI改变信息获取方式，图书馆员的信息素养角色自然延伸到AI素养辅导，B选项准确体现了图书馆专业价值。', NULL, 3, NULL, 'null', NULL, NULL, NULL, 'draft', 0, NULL, NULL, NULL, NULL, 'f153e781-dca0-46af-8430-a62aa9b59a9b', NULL, '2026-04-14 02:25:06.880244+00', '2026-04-14 02:25:06.880249+00');
INSERT INTO public.questions VALUES ('26d90a63-d63b-4e0d-bfb6-b1c07fb23499', 'single_choice', '以下哪项不属于AI素养的基本内涵？（　　）', '{"A": "了解AI的基本工作原理和局限性", "B": "能够批判性地判断AI生成内容的可信度", "C": "掌握训练大语言模型的深度学习算法", "D": "具备在实际场景中负责任地使用AI的意识"}', 'C', 'AI素养强调认知、评估和伦理应用，不要求掌握深度学习算法等专业技术开发能力。', NULL, 3, NULL, 'null', NULL, NULL, NULL, 'draft', 0, NULL, NULL, NULL, NULL, 'f153e781-dca0-46af-8430-a62aa9b59a9b', NULL, '2026-04-14 02:25:06.884372+00', '2026-04-14 02:25:06.884377+00');
INSERT INTO public.questions VALUES ('a451640c-dcb0-47c1-86d0-f6aeab82811b', 'single_choice', '图书馆想用AI自动为新采购的图书添加主题词。最合理的工作流程是（　　）：', '{"A": "AI直接生成主题词并自动导入系统，无需人工干预", "B": "AI生成主题词建议，由专业馆员审核后再导入系统", "C": "完全不使用AI，所有主题词由馆员手工录入", "D": "随机抽取10%的条目请馆员检查，其余直接导入"}', 'B', 'AI辅助加专业人工审核是当前AI在知识组织工作中的最佳实践，兼顾效率与质量控制。', NULL, 3, NULL, 'null', NULL, NULL, NULL, 'draft', 0, NULL, NULL, NULL, NULL, 'f153e781-dca0-46af-8430-a62aa9b59a9b', NULL, '2026-04-14 02:25:06.888546+00', '2026-04-14 02:25:06.88855+00');
INSERT INTO public.questions VALUES ('c1faf15f-7ff4-4dcc-a3c1-7bb92b9ff820', 'single_choice', '以下关于开源AI模型的说法，哪个是正确的？（　　）', '{"A": "开源AI模型的训练数据一定是完全公开透明的", "B": "开源AI模型通常指模型权重公开，但训练数据不一定公开", "C": "开源AI模型不存在版权和伦理问题", "D": "开源AI模型的性能一定比商业模型差"}', 'B', '开源通常指权重公开，训练数据多数不公开，不能以开源推断数据透明或无伦理问题。', NULL, 3, NULL, 'null', NULL, NULL, NULL, 'draft', 0, NULL, NULL, NULL, NULL, 'f153e781-dca0-46af-8430-a62aa9b59a9b', NULL, '2026-04-14 02:25:06.893155+00', '2026-04-14 02:25:06.893164+00');
INSERT INTO public.questions VALUES ('4586ff9e-dca9-4323-ad13-03ece8a814c5', 'single_choice', '某读者希望用AI工具帮助自己完成毕业论文，问馆员有什么建议。以下哪条建议最为恰当？（　　）', '{"A": "AI写的都是垃圾，千万别用", "B": "可以用AI辅助查找思路、整理格式，但核心论点、文献核实和写作必须自己完成，并了解所在学校的AI使用规范", "C": "让AI直接写，改一改就行了，老师也看不出来", "D": "AI工具只能用于理工科，文科论文不适合用"}', 'B', '合理利用AI辅助同时坚守学术诚信，是图书馆信息素养教育的核心主张，B选项体现了负责任的立场。', NULL, 3, NULL, 'null', NULL, NULL, NULL, 'draft', 0, NULL, NULL, NULL, NULL, 'f153e781-dca0-46af-8430-a62aa9b59a9b', NULL, '2026-04-14 02:25:06.899423+00', '2026-04-14 02:25:06.899456+00');
INSERT INTO public.questions VALUES ('becbda5e-9d35-49be-b8da-677ec1fee0e2', 'short_answer', '请用一个日常生活类比，向不懂技术的读者解释【AI幻觉】是怎么回事，以及读者在使用AI检索文献时应如何防范？
INSERT INTO public.questions VALUES ('cf5d9f43-c5d9-4e00-96f0-d890b099a7f6', 'short_answer', '读者反映AI检索工具比图书馆数据库【好用多了】，你作为馆员怎么看待这种说法？AI检索和专业文献数据库各有什么优势？
INSERT INTO public.questions VALUES ('9b917016-c5e7-4fc0-84c6-f9430d41365c', 'true_false', '欧盟人工智能法案（EU AI Act）将图书馆的AI参考咨询系统归类为高风险AI系统，需要强制进行合规评估。（　　）', '{"F": "错误", "T": "正确"}', 'F', 'EU AI Act对图书馆AI参考咨询系统未明确列入高风险类别；教育、劳动力管理、执法等领域才是高风险重点。', NULL, 3, NULL, 'null', NULL, NULL, NULL, 'draft', 0, NULL, NULL, NULL, NULL, 'f153e781-dca0-46af-8430-a62aa9b59a9b', NULL, '2026-04-14 02:28:11.182606+00', '2026-04-14 02:28:11.18261+00');
INSERT INTO public.questions VALUES ('4af37e26-77b4-48fe-bcf9-2a6475aa2e1d', 'short_answer', '如果本馆要开展一场面向普通读者的【AI工具使用注意事项】讲座，你认为最应该讲哪三个要点？请简要列举并说明理由。
INSERT INTO public.questions VALUES ('355cb32f-6b0a-48b1-853d-cab8065ffb4c', 'short_answer', '一位馆员建议将读者借阅和检索行为数据提供给AI模型公司用于训练，以换取免费使用权限。请从读者隐私和职业伦理角度分析这一做法是否合理。
INSERT INTO public.questions VALUES ('ef89020e-7194-466f-9b39-c113add39177', 'short_answer', '在你目前的工作岗位中，AI可以在哪一个环节帮助你提高效率？同时，哪个工作环节最不适合让AI替代？请结合实际说明理由。
INSERT INTO public.questions VALUES ('3a172896-ba7d-446e-98a9-8782bad504e0', 'true_false', 'RAG（检索增强生成）技术可以让大语言模型在回答时直接调取本馆知识库内容，从而有效减少幻觉和知识过时问题。（　　）', '{"F": "错误", "T": "正确"}', 'T', 'RAG将外部知识库与LLM结合，通过实时检索本馆文档后再生成回答，显著降低幻觉率和知识过时风险，是图书馆AI应用的主流架构。', NULL, 3, NULL, 'null', NULL, NULL, NULL, 'draft', 0, NULL, NULL, NULL, NULL, 'f153e781-dca0-46af-8430-a62aa9b59a9b', NULL, '2026-04-14 02:26:56.428198+00', '2026-04-14 02:26:56.428204+00');
INSERT INTO public.questions VALUES ('8ff372dd-b1b3-4af8-80c8-a503545471e8', 'true_false', '图书馆使用AI辅助工具进行参考咨询时，无需向读者说明答案来源，因为最终质量由馆员把关即可。（　　）', '{"F": "错误", "T": "正确"}', 'F', 'AI参与服务应遵循透明度原则，读者有权了解信息是否为AI生成，这是图书馆信息伦理的基本要求，即使馆员把关也不能替代透明告知。', NULL, 3, NULL, 'null', NULL, NULL, NULL, 'draft', 0, NULL, NULL, NULL, NULL, 'f153e781-dca0-46af-8430-a62aa9b59a9b', NULL, '2026-04-14 02:26:56.4326+00', '2026-04-14 02:26:56.432608+00');
INSERT INTO public.questions VALUES ('4ddcaa24-3392-40db-8151-e421be4584b6', 'true_false', '向量数据库（Vector Database）在语义检索中的作用，类似于传统倒排索引在关键词检索中的作用。（　　）', '{"F": "错误", "T": "正确"}', 'T', '向量数据库存储文本嵌入向量，实现语义相似度检索，其角色类似于倒排索引在关键词检索中的作用，但检索逻辑从精确匹配变为向量近邻搜索。', NULL, 3, NULL, 'null', NULL, NULL, NULL, 'draft', 0, NULL, NULL, NULL, NULL, 'f153e781-dca0-46af-8430-a62aa9b59a9b', NULL, '2026-04-14 02:26:56.435884+00', '2026-04-14 02:26:56.435888+00');
INSERT INTO public.questions VALUES ('b8059cdc-7272-4bd3-b09b-2543c71bb8f7', 'true_false', 'AI生成的馆藏目录描述（如内容简介）属于AI独立创作，受现行著作权法自动保护，图书馆拥有相关权利。（　　）', '{"F": "错误", "T": "正确"}', 'F', '各国主流法律不承认AI独立创作的著作权，生成的馆藏描述属于无主权状态或由人类编辑享有权利，图书馆不能以此对外授权。', NULL, 3, NULL, 'null', NULL, NULL, NULL, 'draft', 0, NULL, NULL, NULL, NULL, 'f153e781-dca0-46af-8430-a62aa9b59a9b', NULL, '2026-04-14 02:26:56.439646+00', '2026-04-14 02:26:56.439651+00');
INSERT INTO public.questions VALUES ('e87416c8-7094-4848-a5b3-53728ffbfae8', 'true_false', '提示注入（Prompt Injection）攻击是指恶意用户通过精心设计的输入，诱导AI系统执行超出预期的操作，这对图书馆AI服务具有实际安全风险。（　　）', '{"F": "错误", "T": "正确"}', 'T', '提示注入是真实的AI安全威胁，恶意输入可能绕过AI的安全策略，在图书馆AI服务中可能导致信息泄露或系统被滥用。', NULL, 3, NULL, 'null', NULL, NULL, NULL, 'draft', 0, NULL, NULL, NULL, NULL, 'f153e781-dca0-46af-8430-a62aa9b59a9b', NULL, '2026-04-14 02:26:56.444274+00', '2026-04-14 02:26:56.44428+00');
INSERT INTO public.questions VALUES ('634e23fd-16aa-46ca-82f6-3015fc518c31', 'true_false', '大语言模型的上下文窗口（Context Window）越大，模型处理长文档的能力越强，但对硬件和计算资源的消耗也越高。（　　）', '{"F": "错误", "T": "正确"}', 'T', '上下文窗口越大，推理时内存占用和计算成本线性甚至超线性增长，这是实际部署中的关键约束。', NULL, 3, NULL, 'null', NULL, NULL, NULL, 'draft', 0, NULL, NULL, NULL, NULL, 'f153e781-dca0-46af-8430-a62aa9b59a9b', NULL, '2026-04-14 02:26:56.448371+00', '2026-04-14 02:26:56.448378+00');
INSERT INTO public.questions VALUES ('1f6e8f66-91f0-43a8-9846-f65f1d76e9b4', 'true_false', '图书馆采购AI数据库工具时，供应商声称【基于深度学习】的产品，其学术文献查重准确率一定优于传统规则匹配方法。（　　）', '{"F": "错误", "T": "正确"}', 'F', '基于深度学习是技术路线声明，不等于准确率保证；深度学习在某些精确匹配任务上不一定优于规则方法，需实际评测验证。', NULL, 3, NULL, 'null', NULL, NULL, NULL, 'draft', 0, NULL, NULL, NULL, NULL, 'f153e781-dca0-46af-8430-a62aa9b59a9b', NULL, '2026-04-14 02:26:56.452761+00', '2026-04-14 02:26:56.452765+00');
INSERT INTO public.questions VALUES ('e0124b24-8904-44f2-b188-1af70f40cdfa', 'true_false', '在为读者提供AI工具使用培训时，馆员有责任讲解AI在生成内容方面的局限性，而不仅仅展示AI的便利功能。（　　）', '{"F": "错误", "T": "正确"}', 'T', '图书馆AI素养培训必须包含批判性认知和风险教育，单纯展示便利性而不讲局限性，会强化读者对AI的过度依赖。', NULL, 3, NULL, 'null', NULL, NULL, NULL, 'draft', 0, NULL, NULL, NULL, NULL, 'f153e781-dca0-46af-8430-a62aa9b59a9b', NULL, '2026-04-14 02:26:56.456532+00', '2026-04-14 02:26:56.456537+00');
INSERT INTO public.questions VALUES ('13da9fa3-4b05-4405-a44a-dc9d74d31a87', 'true_false', '模型微调（Fine-tuning）需要大量GPU算力，因此即使拥有本馆历史咨询数据，中小型图书馆也几乎不可能自主开展微调训练。（　　）', '{"F": "错误", "T": "正确"}', 'F', 'LoRA等参数高效微调技术使得在消费级GPU上完成特定领域微调成为可能，中小型图书馆可考虑与高校或云服务合作实现。', NULL, 3, NULL, 'null', NULL, NULL, NULL, 'draft', 0, NULL, NULL, NULL, NULL, 'f153e781-dca0-46af-8430-a62aa9b59a9b', NULL, '2026-04-14 02:26:56.461176+00', '2026-04-14 02:26:56.461182+00');
INSERT INTO public.questions VALUES ('96b43a00-385a-47bf-bae3-c62977c63936', 'true_false', '如果一个AI助手能够准确引用中国国家标准（GB）文件，就可以认定其检索结果可信，馆员无需再行核实。（　　）', '{"F": "错误", "T": "正确"}', 'F', 'AI幻觉可能体现为精确引用格式但内容错误，即使文件编号格式正确，具体条款也可能被AI篡改或杜撰，必须核对原始文件。', NULL, 3, NULL, 'null', NULL, NULL, NULL, 'draft', 0, NULL, NULL, NULL, NULL, 'f153e781-dca0-46af-8430-a62aa9b59a9b', NULL, '2026-04-14 02:26:56.46545+00', '2026-04-14 02:26:56.465458+00');
INSERT INTO public.questions VALUES ('e787b2fc-6eed-4e46-be33-fdfb545d4018', 'single_choice', '图书馆正在建设基于AI的智能参考咨询系统。关于人机协同模式，以下哪种设计最为合理？（　　）', '{"A": "AI全权回答，馆员只在读者投诉时介入", "B": "AI处理常见问题并给出初步回复，复杂或高风险咨询自动转接人工馆员", "C": "馆员先回答，AI对回答进行优化后发给读者", "D": "仅在夜间无人值守时开启AI，日间全部人工服务"}', 'B', '人机协同的最优设计是AI处理高频标准问题，人工处理复杂和高风险情形，既保障效率也维护服务质量。', NULL, 3, NULL, 'null', NULL, NULL, NULL, 'draft', 0, NULL, NULL, NULL, NULL, 'f153e781-dca0-46af-8430-a62aa9b59a9b', NULL, '2026-04-14 02:26:56.471176+00', '2026-04-14 02:26:56.471182+00');
INSERT INTO public.questions VALUES ('5e3429d4-175f-4c62-a515-5634b6c13a28', 'true_false', '以国内某大型高校图书馆为例，将全馆参考咨询语料用于内部大模型预训练，在无需任何外部监管的前提下完全合法合规。（　　）', '{"F": "错误", "T": "正确"}', 'F', '预训练语料中可能包含读者隐私数据或受版权保护内容，须经数据安全评估和版权清查，符合数据安全法和个人信息保护法相关规定，无法绕过监管自行决定。', NULL, 3, NULL, 'null', NULL, NULL, NULL, 'draft', 0, NULL, NULL, NULL, NULL, 'f153e781-dca0-46af-8430-a62aa9b59a9b', NULL, '2026-04-14 02:28:11.189764+00', '2026-04-14 02:28:11.189766+00');
INSERT INTO public.questions VALUES ('b476fa02-4ddc-44a8-9bde-45685adc38cb', 'single_choice', '馆员发现图书馆AI对话系统对某类读者群体（如老年读者、少数民族读者）的回答质量明显低于其他群体。这最可能反映了什么问题？（　　）', '{"A": "该类读者的问题过于简单，AI故意降低回答质量", "B": "AI系统的训练数据存在群体偏差，导致模型性能不均等", "C": "该类读者不熟悉AI工具，提问方式有问题", "D": "服务器算力不足，导致部分用户响应变慢"}', 'B', '群体性能差异是AI系统训练数据偏差的典型表现，少数群体在训练数据中的样本不足导致模型泛化能力弱。', NULL, 3, NULL, 'null', NULL, NULL, NULL, 'draft', 0, NULL, NULL, NULL, NULL, 'f153e781-dca0-46af-8430-a62aa9b59a9b', NULL, '2026-04-14 02:26:56.47586+00', '2026-04-14 02:26:56.475865+00');
INSERT INTO public.questions VALUES ('ade0f8fb-c041-47c0-866b-5107e7caa48c', 'single_choice', '以下关于语义检索与关键词检索的比较，哪个说法最为准确？（　　）', '{"A": "语义检索完全取代关键词检索，图书馆无需再维护传统主题词表", "B": "语义检索通过理解查询意图来匹配相关内容，更擅长处理自然语言提问，但在专业术语精确检索场景中仍有局限", "C": "语义检索的查全率一定高于关键词检索", "D": "关键词检索已完全过时，只有非专业用户才会使用"}', 'B', '语义检索擅长处理意图模糊的自然语言查询，但在精确专业术语检索中仍有不足，两者应结合使用而非替代。', NULL, 3, NULL, 'null', NULL, NULL, NULL, 'draft', 0, NULL, NULL, NULL, NULL, 'f153e781-dca0-46af-8430-a62aa9b59a9b', NULL, '2026-04-14 02:26:56.480263+00', '2026-04-14 02:26:56.480268+00');
INSERT INTO public.questions VALUES ('e46f5596-2af6-4c9e-880e-6bbe43dba339', 'single_choice', '某高校图书馆计划引入AI工具，自动分析全校师生的文献检索行为数据，以优化馆藏采购决策。以下哪项伦理审查最为关键？（　　）', '{"A": "分析结果是否比馆员人工判断更准确", "B": "AI工具的价格是否在采购预算范围内", "C": "是否获得师生知情同意，数据处理是否符合隐私保护法规", "D": "该AI工具是否为国内厂商生产"}', 'C', '使用用户行为数据必须首先解决知情同意和合规问题，这是数据伦理的红线，优先于准确性和成本等技术商业考量。', NULL, 3, NULL, 'null', NULL, NULL, NULL, 'draft', 0, NULL, NULL, NULL, NULL, 'f153e781-dca0-46af-8430-a62aa9b59a9b', NULL, '2026-04-14 02:26:56.484719+00', '2026-04-14 02:26:56.484725+00');
INSERT INTO public.questions VALUES ('560e03e7-7a46-4898-ad67-633cf9ba58be', 'single_choice', '以下哪个概念的解释是错误的？（　　）', '{"A": "知识图谱（Knowledge Graph）是一种以实体和关系为核心的结构化知识表示方式，可用于增强文献关联检索", "B": "嵌入模型（Embedding Model）将文本转化为数字向量，使计算机能够计算文本间的语义相似度", "C": "大语言模型的温度参数（Temperature）越高，生成内容越保守、越接近标准答案", "D": "AI Agent（智能体）具备规划、调用工具、记忆和反思等能力，能完成多步骤复杂任务"}', 'C', '温度参数越高，生成内容随机性越大；温度越低才越保守、越确定。C选项描述与实际相反。', NULL, 3, NULL, 'null', NULL, NULL, NULL, 'draft', 0, NULL, NULL, NULL, NULL, 'f153e781-dca0-46af-8430-a62aa9b59a9b', NULL, '2026-04-14 02:26:56.488992+00', '2026-04-14 02:26:56.488996+00');
INSERT INTO public.questions VALUES ('cefd0687-2d84-4547-80de-df997c7bce02', 'single_choice', '图书馆引入AI生成服务时，哪项透明度要求对读者最为重要？（　　）', '{"A": "公开AI供应商的商业利润信息", "B": "告知读者哪些服务由AI生成或辅助生成，以便读者对信息质量做出自主判断", "C": "公开AI模型的所有技术参数和训练细节", "D": "要求AI的每一条回复都注明生成时间戳"}', 'B', '读者知情权是AI服务透明度的核心，需告知哪些服务由AI生成，使读者能据此调整信任程度和核实力度。', NULL, 3, NULL, 'null', NULL, NULL, NULL, 'draft', 0, NULL, NULL, NULL, NULL, 'f153e781-dca0-46af-8430-a62aa9b59a9b', NULL, '2026-04-14 02:26:56.493257+00', '2026-04-14 02:26:56.493261+00');
INSERT INTO public.questions VALUES ('3cd5c968-f6c2-4e96-b8d0-44c827bd89c4', 'single_choice', '一名馆员在使用AI工具处理一批古籍书目信息时，发现AI将【清】（朝代）误识别为【清洁】，导致主题分类错误。这说明了AI在文献工作中存在什么局限性？（　　）', '{"A": "AI无法处理中文文本", "B": "AI缺乏专业领域的上下文理解能力，容易在专指性强的专业术语上产生歧义", "C": "AI的运行速度太慢，无法满足实际工作需求", "D": "AI只能处理当代文献，无法识别古籍"}', 'B', 'AI缺乏领域专业上下文理解能力，对多义词、专有名词、历史文化概念容易产生歧义解读，古籍领域尤为突出。', NULL, 3, NULL, 'null', NULL, NULL, NULL, 'draft', 0, NULL, NULL, NULL, NULL, 'f153e781-dca0-46af-8430-a62aa9b59a9b', NULL, '2026-04-14 02:26:56.497093+00', '2026-04-14 02:26:56.497096+00');
INSERT INTO public.questions VALUES ('ac2324ce-1994-4d98-a688-fc4e67165c81', 'single_choice', '图书馆员小王发现同事每天直接把AI对话内容截图发给读者，没有经过任何核实。最合适的处理方式是（　　）：', '{"A": "向上级举报，这是严重的职业失范行为", "B": "不干涉，这是同事的工作方式，效率也高", "C": "友善地提醒同事AI可能存在幻觉和错误，建议在核实内容后再发给读者", "D": "自己也开始同样操作，这样才能保持团队一致性"}', 'C', '应以专业且友好的方式提醒同事，不是举报也不是不干涉，体现职业伦理和团队责任。', NULL, 3, NULL, 'null', NULL, NULL, NULL, 'draft', 0, NULL, NULL, NULL, NULL, 'f153e781-dca0-46af-8430-a62aa9b59a9b', NULL, '2026-04-14 02:26:56.502412+00', '2026-04-14 02:26:56.502418+00');
INSERT INTO public.questions VALUES ('63d9a93e-35be-4a17-8290-396858179b74', 'single_choice', '图书馆希望利用AI技术改善视障读者的信息服务，以下哪种方案最具可行性且最符合包容性设计原则？（　　）', '{"A": "为视障读者开设专用图书馆，配备所有AI设备", "B": "在现有服务系统中集成文字转语音、多模态内容理解等AI功能，降低访问门槛", "C": "视障读者只能通过人工馆员服务，AI工具不适合他们使用", "D": "用AI将所有馆藏转化为盲文文件后发放"}', 'B', '将AI无障碍功能集成到现有服务体系是包容性设计的核心思路，降低访问门槛而非建立隔离服务。', NULL, 3, NULL, 'null', NULL, NULL, NULL, 'draft', 0, NULL, NULL, NULL, NULL, 'f153e781-dca0-46af-8430-a62aa9b59a9b', NULL, '2026-04-14 02:26:56.507317+00', '2026-04-14 02:26:56.507323+00');
INSERT INTO public.questions VALUES ('36d45e3a-97e4-40cd-bd35-b7e6f7c66d2f', 'single_choice', '某数据供应商宣传其AI文献推荐系统使用了最先进的Transformer模型，准确率达99%。图书馆在评估采购时，最应该追问的是（　　）：', '{"A": "该模型的参数量是否超过1000亿", "B": "准确率99%是在什么测试集上、用什么指标测量的，测试场景是否与本馆实际需求匹配", "C": "该模型是否使用了GPU而非CPU进行推理", "D": "供应商是否为上市公司"}', 'B', '评估AI性能宣传时，必须追问测试条件、指标定义和场景匹配性，避免被脱离语境的数字误导。', NULL, 3, NULL, 'null', NULL, NULL, NULL, 'draft', 0, NULL, NULL, NULL, NULL, 'f153e781-dca0-46af-8430-a62aa9b59a9b', NULL, '2026-04-14 02:26:56.512327+00', '2026-04-14 02:26:56.512331+00');
INSERT INTO public.questions VALUES ('36b5928c-bee9-4167-8b16-c87440c8b4af', 'short_answer', '某高校图书馆计划引入一套AI智能参考咨询系统，宣称可以回答80%的读者日常咨询问题。请从图书馆服务质量和专业伦理角度，分析该系统落地前需要解决哪些关键问题。
INSERT INTO public.questions VALUES ('505e8b2a-8d6f-4c51-b709-38cda84199c5', 'true_false', '大语言模型存在的位置偏差（Position Bias）是指模型对同一批信息，会因其在上下文中出现的位置不同（首尾vs中间）而给予不同权重，这会影响基于LLM的文献重排（Reranking）结果的可靠性。（　　）', '{"F": "错误", "T": "正确"}', 'T', 'LLM的位置偏差（Lost-in-the-Middle等研究已证实）导致中间位置信息被忽视，影响基于LLM的文献重排可靠性，是RAG系统设计中需特别处理的问题。', NULL, 3, NULL, 'null', NULL, NULL, NULL, 'draft', 0, NULL, NULL, NULL, NULL, 'f153e781-dca0-46af-8430-a62aa9b59a9b', NULL, '2026-04-14 02:28:11.185998+00', '2026-04-14 02:28:11.186003+00');
INSERT INTO public.questions VALUES ('340dd4d5-23ef-4890-a79d-d5ab962b4021', 'short_answer', '大数据与AI技术使个性化推荐成为可能，但也引发了信息茧房（Filter Bubble）担忧。图书馆如果在馆藏推荐服务中引入AI，应如何在个性化与多元化之间取得平衡？
INSERT INTO public.questions VALUES ('12f23046-fad2-4e10-82e7-61eb738c128b', 'short_answer', '你的图书馆准备对全体馆员开展一次AI素养培训。请为以下三类馆员（一线咨询员、编目馆员、数字资源管理员）分别设计一个最核心的AI能力培训重点，并说明理由。
INSERT INTO public.questions VALUES ('63e10c37-0026-4d35-a8d9-ec3359416c98', 'short_answer', '请分析AI技术对图书馆信息素养教育职能的影响：AI的普及是弱化还是强化了图书馆在信息素养教育中的作用？请给出你的判断并说明理由。
INSERT INTO public.questions VALUES ('3b442252-68a9-4a03-bd92-e1c71fece0fb', 'short_answer', '某知名AI公司希望与你馆合作，以免费使用AI工具三年换取使用本馆历史参考咨询记录（已脱敏）训练其模型。请从数据主权、读者权益和机构利益角度，综合分析是否应该接受这一合作。
INSERT INTO public.questions VALUES ('343d8c4d-448f-476b-8643-68109d8c2582', 'true_false', '模型坍塌（Model Collapse）现象是指，如果大语言模型持续在AI生成的数据上训练，将导致模型多样性下降和性能退化，这对未来依赖网络爬取数据的AI训练构成长期威胁。（　　）', '{"F": "错误", "T": "正确"}', 'T', '模型坍塌是真实风险：若未来训练数据中AI生成内容占比过高，将形成信息回音壁，导致语言多样性和事实锚定能力退化。', NULL, 3, NULL, 'null', NULL, NULL, NULL, 'draft', 0, NULL, NULL, NULL, NULL, 'f153e781-dca0-46af-8430-a62aa9b59a9b', NULL, '2026-04-14 02:28:11.19258+00', '2026-04-14 02:28:11.192582+00');
INSERT INTO public.questions VALUES ('8a528769-5208-421a-a706-0391929299d3', 'true_false', '图书馆使用本地部署的开源大模型（如Llama、Qwen）处理读者数据，与调用云端商业API相比，在数据隐私保护方面具有根本性优势，无需额外的安全审查。（　　）', '{"F": "错误", "T": "正确"}', 'F', '本地部署减少了数据外传风险，但不等于无需审查：模型可能存在后门、本地环境存在访问控制问题，安全审查仍然必要。根本性优势的说法过于绝对。', NULL, 3, NULL, 'null', NULL, NULL, NULL, 'draft', 0, NULL, NULL, NULL, NULL, 'f153e781-dca0-46af-8430-a62aa9b59a9b', NULL, '2026-04-14 02:28:11.196024+00', '2026-04-14 02:28:11.196029+00');
INSERT INTO public.questions VALUES ('7667b59e-2ba8-457d-8cbf-dddad7be9b6a', 'true_false', '思维链提示（Chain-of-Thought Prompting）能显著提高大语言模型在逻辑推理任务上的表现，其主要原因是让模型在生成最终答案前先输出中间推理步骤。（　　）', '{"F": "错误", "T": "正确"}', 'T', 'CoT通过引导模型显式化中间推理过程，让每一步逻辑可被后续步骤约束，从而减少跳步错误，已有大量实验研究支持。', NULL, 3, NULL, 'null', NULL, NULL, NULL, 'draft', 0, NULL, NULL, NULL, NULL, 'f153e781-dca0-46af-8430-a62aa9b59a9b', NULL, '2026-04-14 02:28:11.199177+00', '2026-04-14 02:28:11.199184+00');
INSERT INTO public.questions VALUES ('337cf4ca-45ba-447d-a544-c09b37214f87', 'true_false', '在学科服务场景中，AI工具辅助文献计量分析的可靠性，与其依赖的元数据来源质量高度相关；因此提升AI分析质量的首要步骤是确保输入数据质量，而非调整AI模型本身。（　　）', '{"F": "错误", "T": "正确"}', 'T', '垃圾进垃圾出原则在AI文献计量分析中同样适用，低质量元数据会系统性低估相关学者影响力，优先改善输入数据质量最具性价比。', NULL, 3, NULL, 'null', NULL, NULL, NULL, 'draft', 0, NULL, NULL, NULL, NULL, 'f153e781-dca0-46af-8430-a62aa9b59a9b', NULL, '2026-04-14 02:28:11.202566+00', '2026-04-14 02:28:11.202572+00');
INSERT INTO public.questions VALUES ('f3e8277e-a7f9-4912-b50c-a1cfda1a9be5', 'true_false', '幻觉率（Hallucination Rate）是大语言模型的一个标准化基准指标，各主流模型均采用相同的测量方法，可以直接横向比较。（　　）', '{"F": "错误", "T": "正确"}', 'F', '目前学界尚无统一的幻觉率测量标准，不同评测体系（TruthfulQA、HaluEval等）使用不同任务和标注方式，横向比较必须注明前提条件。', NULL, 3, NULL, 'null', NULL, NULL, NULL, 'draft', 0, NULL, NULL, NULL, NULL, 'f153e781-dca0-46af-8430-a62aa9b59a9b', NULL, '2026-04-14 02:28:11.20674+00', '2026-04-14 02:28:11.206744+00');
INSERT INTO public.questions VALUES ('852a7b10-a4b4-4598-a0aa-b3bf5c36090e', 'true_false', '图书馆在制定AI伦理治理框架时，仅参照新一代人工智能治理原则（2019）和联合国教科文组织AI伦理建议书（2021）即可满足当前国内监管要求。（　　）', '{"F": "错误", "T": "正确"}', 'F', '当前国内AI监管体系已新增生成式人工智能服务管理暂行办法（2023）等文件，仅参照2019/2021年文件不足以满足现行合规要求。', NULL, 3, NULL, 'null', NULL, NULL, NULL, 'draft', 0, NULL, NULL, NULL, NULL, 'f153e781-dca0-46af-8430-a62aa9b59a9b', NULL, '2026-04-14 02:28:11.209911+00', '2026-04-14 02:28:11.209915+00');
INSERT INTO public.questions VALUES ('e77c3bf3-ac68-4107-b6b1-e8806369a655', 'single_choice', '图书馆计划构建一个基于RAG架构的学科知识问答系统。在分块策略（Chunking Strategy）的设计上，以下哪种考量最为关键？（　　）', '{"A": "分块越小越好，便于精确匹配", "B": "分块应使语义单元保持完整，同时与嵌入模型的最优处理长度相匹配，过大或过小均会影响检索召回质量", "C": "统一使用512个token作为所有文档的分块长度", "D": "中文文献按段落分块，英文文献按句子分块"}', 'B', '分块策略需平衡语义完整性与模型处理效率，与嵌入模型最优输入长度匹配是关键约束，A过于简化，C/D是固定规则而非原则性考量。', NULL, 3, NULL, 'null', NULL, NULL, NULL, 'draft', 0, NULL, NULL, NULL, NULL, 'f153e781-dca0-46af-8430-a62aa9b59a9b', NULL, '2026-04-14 02:28:11.214966+00', '2026-04-14 02:28:11.21497+00');
INSERT INTO public.questions VALUES ('c300b6d3-96fc-4a05-967d-f4ea21635c62', 'single_choice', '某学科馆员利用AI辅助分析一批学者的学术合作网络，发现AI给某位学者的跨学科影响力打分显著低于同行评价。最可能的技术原因是（　　）：', '{"A": "AI系统对该学者存在个人偏见", "B": "该学者的跨学科发表分散在AI训练数据中覆盖较少的小众期刊和新兴领域，导致引用数据稀疏，影响模型评估", "C": "AI计算能力不足，无法处理复杂的合作关系", "D": "该学者的研究领域属于高风险领域，AI系统主动降低其评分"}', 'B', '小众期刊和新兴领域在训练数据中的覆盖稀疏是AI文献分析中的典型偏差来源，这是数据代表性问题而非算力或个人偏见问题。', NULL, 3, NULL, 'null', NULL, NULL, NULL, 'draft', 0, NULL, NULL, NULL, NULL, 'f153e781-dca0-46af-8430-a62aa9b59a9b', NULL, '2026-04-14 02:28:11.217777+00', '2026-04-14 02:28:11.217781+00');
INSERT INTO public.questions VALUES ('46ff10c7-2b72-4d5f-bf14-4fa7d6c75bac', 'single_choice', '在评估一套AI驱动的学术不端检测系统时，以下哪个指标组合最能全面反映其实际可用性？（　　）', '{"A": "准确率（Precision）和召回率（Recall），并明确测试集的来源和标注方式", "B": "只看准确率，因为误判会伤害学生", "C": "只看是否使用了GPT-4作为基础模型", "D": "看供应商的客户案例数量"}', 'A', '评估AI学术不端检测系统需同时看查准率和查全率，且测试集来源和标注方式必须透明才能保证评估可信度。', NULL, 3, NULL, 'null', NULL, NULL, NULL, 'draft', 0, NULL, NULL, NULL, NULL, 'f153e781-dca0-46af-8430-a62aa9b59a9b', NULL, '2026-04-14 02:28:11.221715+00', '2026-04-14 02:28:11.22172+00');
INSERT INTO public.questions VALUES ('843c7d24-ee1a-4f7d-8f2b-6ad92deba29f', 'single_choice', '图书馆在开展数字人文项目中，希望用AI对大量历史档案进行自动标注。以下哪种工作流程最符合人文学科的严谨性要求？（　　）', '{"A": "AI全自动标注后直接归档，利用AI的规模优势", "B": "AI生成初步标注，领域专家进行批量审核并记录纠错过程，将纠错数据用于持续优化模型", "C": "仅人工标注，AI不参与人文学科项目", "D": "AI标注后做随机抽样，抽样比例5%以上即可"}', 'B', 'AI加专家审核加纠错数据回流是人文学科AI辅助标注的最佳实践，既发挥AI规模优势，又保障学术严谨性，并通过持续学习提升质量。', NULL, 3, NULL, 'null', NULL, NULL, NULL, 'draft', 0, NULL, NULL, NULL, NULL, 'f153e781-dca0-46af-8430-a62aa9b59a9b', NULL, '2026-04-14 02:28:11.225006+00', '2026-04-14 02:28:11.225011+00');
INSERT INTO public.questions VALUES ('2d6c9edc-eb56-422d-842e-11c80c314476', 'single_choice', '以下关于对齐税（Alignment Tax）概念的解释，哪个最准确？（　　）', '{"A": "使用AI工具的企业需要缴纳额外的政府税款", "B": "为使AI遵循人类价值观所做的安全对齐训练，可能导致模型在部分基准任务上的性能相较于未对齐版本有所下降", "C": "对齐税是指AI公司花费在合规上的额外成本", "D": "这是一个已被证伪的概念，安全对齐不会影响模型性能"}', 'B', '对齐税指安全训练带来的性能代价，是AI安全研究中被实证讨论的真实现象，B准确表达了有条件的描述。', NULL, 3, NULL, 'null', NULL, NULL, NULL, 'draft', 0, NULL, NULL, NULL, NULL, 'f153e781-dca0-46af-8430-a62aa9b59a9b', NULL, '2026-04-14 02:28:11.22926+00', '2026-04-14 02:28:11.229265+00');
INSERT INTO public.questions VALUES ('901ac79b-e71a-4111-ba31-920c3eda61e4', 'single_choice', '图书馆向上级机构申请AI+智慧图书馆专项经费。以下哪种论证框架最具说服力？（　　）', '{"A": "以AI技术先进性为主要论点，强调引进最新大模型", "B": "以读者服务改善和馆藏利用率提升为核心，辅以可量化的预期指标，并说明数据隐私保护和风险管理方案", "C": "仅以降低人力成本为核心诉求", "D": "以竞争对手已引入AI为主要理由"}', 'B', '经费申请应以读者价值和可量化指标为核心，辅以风险管理方案，这是技术投资合理性论证的最有力框架。', NULL, 3, NULL, 'null', NULL, NULL, NULL, 'draft', 0, NULL, NULL, NULL, NULL, 'f153e781-dca0-46af-8430-a62aa9b59a9b', NULL, '2026-04-14 02:28:11.232788+00', '2026-04-14 02:28:11.232792+00');
INSERT INTO public.questions VALUES ('63b835f8-af2d-46a6-b08a-724b895f62f7', 'single_choice', '以下哪种情形属于图书馆AI应用中真正需要进行算法审计（Algorithmic Audit）的场景？（　　）', '{"A": "AI辅助馆员撰写书目摘要", "B": "AI系统用于自动筛选文献采购候选名单，且该名单直接影响特定学科经费分配", "C": "使用AI工具批量翻译外文新闻", "D": "馆员使用AI辅助工具制作PPT演示文稿"}', 'B', '算法审计应针对影响资源分配等高风险决策的AI系统，B选项中的采购筛选直接影响经费分配，属于需要透明度和公平性监督的场景。', NULL, 3, NULL, 'null', NULL, NULL, NULL, 'draft', 0, NULL, NULL, NULL, NULL, 'f153e781-dca0-46af-8430-a62aa9b59a9b', NULL, '2026-04-14 02:28:11.236272+00', '2026-04-14 02:28:11.236277+00');
INSERT INTO public.questions VALUES ('b2661617-3e28-4ab3-867d-39d67f2f2616', 'single_choice', '图书馆学科馆员小周使用AI工具为理工科教授生成了一份本领域五年研究热点报告。教授指出报告遗漏了该领域最重要的几个会议和顶级期刊的最新发现。最可能的技术原因是（　　）：', '{"A": "AI不擅长分析理工科文献", "B": "AI存在知识截止日期限制，且对该领域顶级会议论文的训练数据覆盖可能不足；同时RAG系统若未接入最新数据库，无法捕获最新发现", "C": "教授要求太高，AI本来就不能替代专家", "D": "小周的提示词不够长"}', 'B', '知识截止和训练数据稀疏是最常见的系统性原因；RAG系统未接入最新数据库则进一步加剧信息缺口，这是学科服务AI工具的核心局限。', NULL, 3, NULL, 'null', NULL, NULL, NULL, 'draft', 0, NULL, NULL, NULL, NULL, 'f153e781-dca0-46af-8430-a62aa9b59a9b', NULL, '2026-04-14 02:28:11.240076+00', '2026-04-14 02:28:11.24008+00');
INSERT INTO public.questions VALUES ('9445ee45-e713-4b0f-9c56-2d0f54c9f2c3', 'single_choice', '以下哪个说法最准确地描述了主权AI（Sovereign AI）概念对国内图书馆数据治理的潜在影响？（　　）', '{"A": "主权AI要求所有图书馆必须自建AI系统，不得使用境外产品", "B": "主权AI强调在国家主权框架内对数据、算法和算力实施管控，要求图书馆评估所用AI系统的数据流向、算法来源及境外依赖程度", "C": "主权AI是一个纯政治概念，与图书馆日常技术工作无关", "D": "主权AI仅适用于军事和政府核心部门，不适用于公共文化机构"}', 'B', '主权AI概念要求对数据流向、算法来源和境外依赖进行评估，图书馆作为公共数据持有者有相应的治理责任。', NULL, 3, NULL, 'null', NULL, NULL, NULL, 'draft', 0, NULL, NULL, NULL, NULL, 'f153e781-dca0-46af-8430-a62aa9b59a9b', NULL, '2026-04-14 02:28:11.243908+00', '2026-04-14 02:28:11.243913+00');
INSERT INTO public.questions VALUES ('368cc9d4-750b-4669-9775-f4a44af8b71e', 'single_choice', 'AI原生图书馆（AI-Native Library）战略转型的倡议在业界引发广泛讨论。以下哪个判断最为审慎？（　　）', '{"A": "AI原生是不可逆转的趋势，图书馆应立即全面替换现有系统", "B": "AI原生转型需要清晰界定内涵，评估馆藏资源、人员能力和读者需求的匹配性，防止将技术噱头凌驾于服务本质之上", "C": "AI原生转型只需引进几个AI工具即可实现", "D": "只有大型国家级图书馆才有能力推进AI原生转型"}', 'B', '战略转型应基于服务本质评估，防止技术噱头凌驾服务本质，是图书馆AI战略的核心警示。', NULL, 3, NULL, 'null', NULL, NULL, NULL, 'draft', 0, NULL, NULL, NULL, NULL, 'f153e781-dca0-46af-8430-a62aa9b59a9b', NULL, '2026-04-14 02:28:11.248694+00', '2026-04-14 02:28:11.248698+00');
INSERT INTO public.questions VALUES ('83b25fff-b9b8-449c-8312-28cfce916fd6', 'short_answer', '近年来多家图书馆在官网部署了基于大语言模型的智能问答机器人。请从幻觉风险管理、服务责任边界、读者信息权利三个维度，分析该类系统的伦理治理难点，并提出一条具体的治理建议。
INSERT INTO public.questions VALUES ('e63f44bd-2ad1-4ef5-8db7-be580004148b', 'short_answer', '有学者提出：图书馆AI素养教育应从工具使用转向批判性AI研究，即不仅教读者如何用AI，还要教读者质疑AI系统背后的权力结构、数据政治和算法偏见。请评价这一观点，并结合图书馆实际条件分析其可行性。
INSERT INTO public.questions VALUES ('18026ea1-1a6d-4d5c-904c-f6cbd4c95f76', 'short_answer', '请论述RAG（检索增强生成）与传统图书馆OPAC检索在知识发现逻辑上的根本差异，并分析RAG技术在大规模古籍数字化知识服务场景中的核心挑战（至少三点）。
INSERT INTO public.questions VALUES ('cc75b08b-0480-41a6-a2bb-2b4f7a46c01a', 'short_answer', '国内某省级公共图书馆计划将其AI辅助服务系统提交政府数据安全合规审查。请从数据安全法、个人信息保护法和生成式人工智能服务管理暂行办法三部法规的角度，各提出一项该系统必须满足的合规要求。
INSERT INTO public.questions VALUES ('10f8b232-06a1-4501-bba5-8d398160dfaf', 'short_answer', '请批判性地分析以下论断：AI将使图书馆员从信息守门人转变为信息向导（Curator to Navigator），这一转型将深刻重塑图书馆的专业价值。你同意这一判断吗？请从职业角色演变和专业能力重构两个维度给出你的分析。
INSERT INTO public.questions VALUES ('3ae3b294-a5c7-4d59-9e51-bbc0abbd015f', 'true_false', '大语言模型的参数量越大，其产生幻觉（Hallucination）的概率就越低。（　　）', '{"F": "错误", "T": "正确"}', 'F', '更大的模型往往更自信地输出错误内容，幻觉问题与参数量并非简单负相关；大模型有时会以更高的置信度产生幻觉。', NULL, 3, NULL, 'null', NULL, NULL, NULL, 'draft', 0, NULL, NULL, NULL, NULL, 'f153e781-dca0-46af-8430-a62aa9b59a9b', NULL, '2026-04-14 02:29:56.270364+00', '2026-04-14 02:29:56.270372+00');
INSERT INTO public.questions VALUES ('01d1023f-8b0a-4078-bb0a-598807729513', 'true_false', '对同一问题多次提问AI，每次都得到完全相同的回答，这说明该答案很可能是正确的。（　　）', '{"F": "错误", "T": "正确"}', 'F', '一致性来自温度参数较低时的确定性生成，与事实准确性无关——AI完全可以一致地重复同一个错误答案。', NULL, 3, NULL, 'null', NULL, NULL, NULL, 'draft', 0, NULL, NULL, NULL, NULL, 'f153e781-dca0-46af-8430-a62aa9b59a9b', NULL, '2026-04-14 02:29:56.274362+00', '2026-04-14 02:29:56.274366+00');
INSERT INTO public.questions VALUES ('2aaabf11-c867-42bd-97c3-37258e02ad0f', 'true_false', 'AI生成的文本只要语法通顺、逻辑流畅，通常意味着其内容是可靠的。（　　）', '{"F": "错误", "T": "正确"}', 'F', '流畅性是LLM的核心能力，与事实准确性相互独立；最危险的幻觉往往表现为极为流畅的错误叙述。', NULL, 3, NULL, 'null', NULL, NULL, NULL, 'draft', 0, NULL, NULL, NULL, NULL, 'f153e781-dca0-46af-8430-a62aa9b59a9b', NULL, '2026-04-14 02:29:56.277591+00', '2026-04-14 02:29:56.277596+00');
INSERT INTO public.questions VALUES ('e668b6b2-feeb-4b9f-98a2-eb0c2e7b80bf', 'true_false', '在提示词中明确指示【请勿编造文献，若不确定请说不知道】，可以完全消除AI的幻觉输出。（　　）', '{"F": "错误", "T": "正确"}', 'F', '指令能减少幻觉但无法消除，LLM的生成机制决定这是概率性问题，无法通过任何提示词从根本上解决。', NULL, 3, NULL, 'null', NULL, NULL, NULL, 'draft', 0, NULL, NULL, NULL, NULL, 'f153e781-dca0-46af-8430-a62aa9b59a9b', NULL, '2026-04-14 02:29:56.280935+00', '2026-04-14 02:29:56.280938+00');
INSERT INTO public.questions VALUES ('c4d3d7e2-8492-4d38-a656-bcf2118d06aa', 'true_false', '使用思维链（Chain-of-Thought）提示技术，AI给出的最终答案一定比不使用时更加准确。（　　）', '{"F": "错误", "T": "正确"}', 'F', '思维链使推理步骤可见，但错误的中间推理步骤会被逐步放大——在某些任务上CoT反而导致准确率下降。', NULL, 3, NULL, 'null', NULL, NULL, NULL, 'draft', 0, NULL, NULL, NULL, NULL, 'f153e781-dca0-46af-8430-a62aa9b59a9b', NULL, '2026-04-14 02:29:56.284046+00', '2026-04-14 02:29:56.284051+00');
INSERT INTO public.questions VALUES ('4b46b1b3-20da-4233-9134-cb59ab4e060f', 'true_false', '如果在对话中向AI提供了一篇完整文章让其总结，AI对文章开头和结尾内容的关注程度通常高于中间部分。（　　）', '{"F": "错误", "T": "正确"}', 'T', '这就是已被实验证实的迷失在中间（Lost-in-the-Middle）现象：LLM对长文本中间部分的注意力权重系统性偏低。', NULL, 3, NULL, 'null', NULL, NULL, NULL, 'draft', 0, NULL, NULL, NULL, NULL, 'f153e781-dca0-46af-8430-a62aa9b59a9b', NULL, '2026-04-14 02:29:56.2879+00', '2026-04-14 02:29:56.287906+00');
INSERT INTO public.questions VALUES ('bf119074-1ea0-498d-aaf1-17fbd85e4de4', 'true_false', '大语言模型在训练数据截止日期之前发生的所有事件，其知识覆盖是完整而均匀的。（　　）', '{"F": "错误", "T": "正确"}', 'F', '训练数据分布高度不均匀，特定领域、语言、时段、文化的内容在训练集中覆盖极少，模型知识存在大量盲区。', NULL, 3, NULL, 'null', NULL, NULL, NULL, 'draft', 0, NULL, NULL, NULL, NULL, 'f153e781-dca0-46af-8430-a62aa9b59a9b', NULL, '2026-04-14 02:29:56.292362+00', '2026-04-14 02:29:56.292367+00');
INSERT INTO public.questions VALUES ('8772bdb0-9ea5-43c6-93eb-fb3baeb805fc', 'true_false', '在使用RAG（检索增强生成）技术后，大语言模型就不会再出现幻觉问题。（　　）', '{"F": "错误", "T": "正确"}', 'F', 'RAG显著降低幻觉率但不能消除：模型仍可能错误使用检索到的文档，或在检索不准确时继续产生幻觉。', NULL, 3, NULL, 'null', NULL, NULL, NULL, 'draft', 0, NULL, NULL, NULL, NULL, 'f153e781-dca0-46af-8430-a62aa9b59a9b', NULL, '2026-04-14 02:29:56.296386+00', '2026-04-14 02:29:56.296391+00');
INSERT INTO public.questions VALUES ('f63b34d7-da4e-49f0-9e89-9136d97a0985', 'true_false', '向同一AI工具发送完全相同的问题，在不同时间或不同对话窗口中得到的回答可能存在实质性差异。（　　）', '{"F": "错误", "T": "正确"}', 'T', '除非温度设为0，LLM的生成本质上是概率采样过程，相同输入可产生不同输出，这是其随机性的正常表现。', NULL, 3, NULL, 'null', NULL, NULL, NULL, 'draft', 0, NULL, NULL, NULL, NULL, 'f153e781-dca0-46af-8430-a62aa9b59a9b', NULL, '2026-04-14 02:29:56.300299+00', '2026-04-14 02:29:56.300304+00');
INSERT INTO public.questions VALUES ('24131013-07e0-40a4-b972-81d292a19f8f', 'true_false', '当AI在回答中使用【据我所知】或【根据我的知识】等表述时，意味着它正在引用经过系统验证的可靠来源。（　　）', '{"F": "错误", "T": "正确"}', 'F', '此类表述只是语言生成风格，LLM没有独立的知识库验证机制，这些词语本身就是生成式输出的一部分。', NULL, 3, NULL, 'null', NULL, NULL, NULL, 'draft', 0, NULL, NULL, NULL, NULL, 'f153e781-dca0-46af-8430-a62aa9b59a9b', NULL, '2026-04-14 02:29:56.304805+00', '2026-04-14 02:29:56.304809+00');
INSERT INTO public.questions VALUES ('454ccaa1-b1e0-47b1-8056-eee63cec6700', 'single_choice', '你向AI询问某历史事件，它给出了一个完全错误但表述极为自信的答案。这最能说明AI的哪个特点？（　　）', '{"A": "AI故意欺骗用户", "B": "AI的训练数据中关于该事件的信息严重不足", "C": "LLM的生成机制使其倾向于产生听起来合理的内容，而非优先保证事实准确性", "D": "AI存在系统性的反人类偏见"}', 'C', 'LLM的生成目标是产生统计上连贯的文本，而非保证事实准确，自信地输出错误内容正是幻觉问题的核心特征。', NULL, 3, NULL, 'null', NULL, NULL, NULL, 'draft', 0, NULL, NULL, NULL, NULL, 'f153e781-dca0-46af-8430-a62aa9b59a9b', NULL, '2026-04-14 02:29:56.309985+00', '2026-04-14 02:29:56.30999+00');
INSERT INTO public.questions VALUES ('5a2fd800-d955-4fe2-aab3-d5bc49ba62d9', 'single_choice', '将提示词从中文改为英文，发给同一个AI模型，以下哪种说法最为准确？（　　）', '{"A": "英文提示词总能得到更好的结果，因为AI训练数据以英文为主", "B": "中文提示词总能得到更好的结果，因为对中国用户更贴近", "C": "结果取决于具体任务：涉及英文知识体系的任务英文可能更优，中文语境相关任务中文可能更佳", "D": "语言选择对AI输出质量没有任何影响"}', 'C', '语言选择的影响因任务而异；不存在绝对优劣，需要根据任务的知识语境来判断。', NULL, 3, NULL, 'null', NULL, NULL, NULL, 'draft', 0, NULL, NULL, NULL, NULL, 'f153e781-dca0-46af-8430-a62aa9b59a9b', NULL, '2026-04-14 02:29:56.314146+00', '2026-04-14 02:29:56.31415+00');
INSERT INTO public.questions VALUES ('f80b0e9e-11e9-4f2a-841c-a174adb903b1', 'single_choice', '大语言模型的温度（Temperature）参数设置为0时，以下哪个描述最为准确？（　　）', '{"A": "模型会拒绝回答任何问题", "B": "模型的输出变得完全随机，每次都不同", "C": "对于相同输入，模型每次都会生成完全相同的输出", "D": "模型的幻觉问题会完全消失"}', 'C', '温度=0意味着模型在每一步都选择概率最高的词，使输出具有确定性，但这与准确性无关，也不消除幻觉。', NULL, 3, NULL, 'null', NULL, NULL, NULL, 'draft', 0, NULL, NULL, NULL, NULL, 'f153e781-dca0-46af-8430-a62aa9b59a9b', NULL, '2026-04-14 02:29:56.31797+00', '2026-04-14 02:29:56.317975+00');
INSERT INTO public.questions VALUES ('441055c2-387e-4432-bba0-4c553799bde8', 'single_choice', '以下哪个场景中，AI产生幻觉的风险最高？（　　）', '{"A": "将你提供的一段中文文本翻译成英文", "B": "总结一篇已完整提供给AI的新闻报道", "C": "描述你口头提到的一位不太知名学者的代表作和学术成就", "D": "将你写好的一段文字改写成更正式的学术语言"}', 'C', '询问没有提供原始资料的不知名人物信息是幻觉的高危场景：AI会编造听起来合理的学术成就和著作。', NULL, 3, NULL, 'null', NULL, NULL, NULL, 'draft', 0, NULL, NULL, NULL, NULL, 'f153e781-dca0-46af-8430-a62aa9b59a9b', NULL, '2026-04-14 02:29:56.322237+00', '2026-04-14 02:29:56.322241+00');
INSERT INTO public.questions VALUES ('8ef6599b-2b88-4367-8bcf-5c3d6f758d59', 'single_choice', '研究生小张用AI分析了20篇文献，发现AI将其中一篇的核心观点描述得与原文截然相反，其余部分看起来都很好。此时最合理的处理方式是（　　）：', '{"A": "只修正那一处错误，其余部分直接使用，错误概率很低", "B": "因为发现了错误，放弃AI辅助，全部重新手工分析", "C": "对每篇文献的AI描述都进行核实，因为一处可见错误往往意味着存在更多不易察觉的错误", "D": "将报告提交导师，附注说明是AI生成"}', 'C', '可见错误是冰山一角：AI可能在多处做出细微但错误的总结，一处明显错误应触发对全部内容的核实。', NULL, 3, NULL, 'null', NULL, NULL, NULL, 'draft', 0, NULL, NULL, NULL, NULL, 'f153e781-dca0-46af-8430-a62aa9b59a9b', NULL, '2026-04-14 02:29:56.32669+00', '2026-04-14 02:29:56.326696+00');
INSERT INTO public.questions VALUES ('fbe3e8a8-2ce6-4e47-9746-44b0bf75dbe1', 'true_false', '提示词写得越长、信息越详细，AI给出的回答质量就一定越高。（　　）', '{"F": "错误", "T": "正确"}', 'F', '过长的提示词会稀释模型注意力，导致关键信息被忽视；迷失在中间现象在提示词本身中同样存在，适当精练反而更有效。', NULL, 3, NULL, 'null', NULL, NULL, NULL, 'draft', 0, NULL, NULL, NULL, NULL, 'f153e781-dca0-46af-8430-a62aa9b59a9b', NULL, '2026-04-14 02:31:25.960511+00', '2026-04-14 02:31:25.960519+00');
INSERT INTO public.questions VALUES ('16e15ed9-9734-4f0d-80fc-f60a40b52f11', 'single_choice', '用AI辅助文献综述时，你发现AI引用了一篇你从未见过的论文，作者、期刊、年份格式完整规范。正确的处理方式是（　　）：', '{"A": "直接采用，完整的格式通常意味着文献真实存在", "B": "在学术数据库中检索，确认该文献是否真实存在", "C": "删除该引用，AI生成的引用百分之百都是虚假的", "D": "先用搜索引擎查该标题，搜到任何相关结果就可采用"}', 'B', '规范的引用格式是AI幻觉的典型特征之一，必须通过数据库检索（如知网、WOS）逐一核实文献真实性。', NULL, 3, NULL, 'null', NULL, NULL, NULL, 'draft', 0, NULL, NULL, NULL, NULL, 'f153e781-dca0-46af-8430-a62aa9b59a9b', NULL, '2026-04-14 02:29:56.331414+00', '2026-04-14 02:29:56.331419+00');
INSERT INTO public.questions VALUES ('1b3e897f-882f-4b7f-92df-22465e73df23', 'single_choice', '某社科研究者发现，用AI分析访谈数据时，AI总是将边缘化受访者的观点归入主流类别，忽略其独特性。这最可能是因为（　　）：', '{"A": "AI没有读完全部访谈文本", "B": "AI的训练数据对多数群体的表达模式给予了更多权重，导致对边缘声音的识别能力偏弱", "C": "访谈数据的语言表达质量太差", "D": "研究者的提示词过于简短"}', 'B', '训练数据的多数群体偏差导致AI对少数或边缘化表达的识别能力系统性偏弱，这是AI偏见的典型机制。', NULL, 3, NULL, 'null', NULL, NULL, NULL, 'draft', 0, NULL, NULL, NULL, NULL, 'f153e781-dca0-46af-8430-a62aa9b59a9b', NULL, '2026-04-14 02:29:56.336118+00', '2026-04-14 02:29:56.336129+00');
INSERT INTO public.questions VALUES ('fccc5c8f-e906-4285-8997-a860c13f2f9d', 'single_choice', '以下哪种行为最能体现AI素养中的批判性使用原则？（　　）', '{"A": "每次使用AI后，在文末注明本文使用了AI工具", "B": "只使用经过官方认证的AI工具", "C": "在采纳AI输出前，依据独立信息源主动验证关键事实和引用", "D": "将AI输出用中文重写一遍，确保语言风格是自己的"}', 'C', '批判性使用的核心是独立核实，而非仅仅在形式上声明使用了AI或更换语言风格。', NULL, 3, NULL, 'null', NULL, NULL, NULL, 'draft', 0, NULL, NULL, NULL, NULL, 'f153e781-dca0-46af-8430-a62aa9b59a9b', NULL, '2026-04-14 02:29:56.340669+00', '2026-04-14 02:29:56.340673+00');
INSERT INTO public.questions VALUES ('73c427ca-cfc2-448e-9f0f-340425da4711', 'single_choice', '以下关于提示注入（Prompt Injection）攻击的描述，哪个最准确？（　　）', '{"A": "这是指在提示词中注入恶意代码，让AI执行计算机病毒", "B": "这是指通过精心设计的输入，覆盖或绕过AI系统的原始安全指令", "C": "这是一种让AI运行更快的技术优化方法", "D": "这仅发生在开源模型中，商业模型已完全免疫"}', 'B', '提示注入通过构造特殊输入绕过AI的系统提示和安全设置，是一种真实且影响广泛的AI安全威胁。', NULL, 3, NULL, 'null', NULL, NULL, NULL, 'draft', 0, NULL, NULL, NULL, NULL, 'f153e781-dca0-46af-8430-a62aa9b59a9b', NULL, '2026-04-14 02:29:56.345417+00', '2026-04-14 02:29:56.345424+00');
INSERT INTO public.questions VALUES ('419870d7-fa51-4de5-b384-59100093a89f', 'single_choice', '以下哪种AI应用场景，幻觉带来的实际风险最低？（　　）', '{"A": "让AI提供某种药物的具体剂量建议", "B": "让AI将你已写好的中文段落改写得更学术化", "C": "让AI描述某位历史上不太知名的哲学家的思想体系", "D": "让AI告诉你某本书是否真实存在"}', 'B', '对已有文本进行风格改写时，幻觉风险低：内容已由用户提供，AI主要做语言层面的处理，无需生成新事实。', NULL, 3, NULL, 'null', NULL, NULL, NULL, 'draft', 0, NULL, NULL, NULL, NULL, 'f153e781-dca0-46af-8430-a62aa9b59a9b', NULL, '2026-04-14 02:29:56.350016+00', '2026-04-14 02:29:56.350021+00');
INSERT INTO public.questions VALUES ('ad2769e3-853d-4b1b-b7b9-ddf6a29dde54', 'multiple_choice', '以下关于大语言模型幻觉（Hallucination）的描述，哪些是正确的？（多选）', '{"A": "幻觉是指AI在没有事实依据的情况下生成听起来合理的虚假内容", "B": "幻觉只发生在开源模型中，主流商业模型已基本消除", "C": "文笔流畅、引用格式规范的AI输出也可能包含幻觉", "D": "更大参数量的模型在某些任务上可能产生更为自信的幻觉", "E": "在提示词中要求AI只输出确定的事实，可以从根本上消除幻觉"}', 'ACD', 'B错误：幻觉存在于所有LLM中，商业模型也不例外；E错误：指令能减少但无法消除幻觉。A、C、D均为有实验支持的准确描述。', NULL, 3, NULL, 'null', NULL, NULL, NULL, 'draft', 0, NULL, NULL, NULL, NULL, 'f153e781-dca0-46af-8430-a62aa9b59a9b', NULL, '2026-04-14 02:29:56.357223+00', '2026-04-14 02:29:56.357229+00');
INSERT INTO public.questions VALUES ('8283b650-49ff-41cd-a1ed-7795e549b5dd', 'multiple_choice', '以下哪些情形属于AI在人文社科研究中可能产生的偏见问题？（多选）', '{"A": "AI在分析非西方文化语境的文本时，可能套用西方理论框架进行解读", "B": "AI在训练数据中见过更多男性学者的名字，可能在学术贡献描述上存在性别偏差", "C": "AI无法理解隐喻和象征，因此必然对一切文学作品产生偏见", "D": "AI对训练数据截止日期之后出现的新兴理论流派缺乏了解", "E": "AI倾向于将边缘化群体的声音归入非主流或异常类别"}', 'ABDE', 'C错误：AI可以处理隐喻，只是准确率有限，不是必然偏见。A、B、D、E均是训练数据代表性不足导致的系统性偏差的真实表现。', NULL, 3, NULL, 'null', NULL, NULL, NULL, 'draft', 0, NULL, NULL, NULL, NULL, 'f153e781-dca0-46af-8430-a62aa9b59a9b', NULL, '2026-04-14 02:29:56.363287+00', '2026-04-14 02:29:56.363293+00');
INSERT INTO public.questions VALUES ('c6bce4a2-0c4f-40ad-b1e9-079e131338f3', 'multiple_choice', '使用AI辅助学术写作时，以下哪些做法符合学术诚信规范？（多选）', '{"A": "用AI将自己写好的中文摘要翻译成英文，经人工校对后使用", "B": "让AI根据论文题目直接生成文献综述，稍加改动后提交", "C": "请AI对自己写好的段落提出语言修改建议，自行决定是否采纳", "D": "使用AI对自己收集的原始访谈数据进行初步编码，再由研究者审核深化", "E": "将AI生成的理论框架直接作为论文核心分析框架，不加标注"}', 'ACD', 'B和E涉及以AI生成内容替代研究者核心智识劳动；A为工具辅助翻译，C为语言建议，D为辅助初步编码后人工审核，均为可接受做法。', NULL, 3, NULL, 'null', NULL, NULL, NULL, 'draft', 0, NULL, NULL, NULL, NULL, 'f153e781-dca0-46af-8430-a62aa9b59a9b', NULL, '2026-04-14 02:29:56.36712+00', '2026-04-14 02:29:56.367126+00');
INSERT INTO public.questions VALUES ('c35df530-3988-4205-8211-4b31abc333de', 'multiple_choice', '以下哪些说法正确描述了大语言模型的技术特点？（多选）', '{"A": "LLM通过预测下一个最可能的词（token）来生成文本，而非通过理解语义", "B": "同一个LLM对同一问题在不同时间的回答可能不同（温度参数大于0时）", "C": "LLM在对话中能真正记住与某用户过去所有对话的内容", "D": "LLM的生成结果受到提示词措辞细微变化的影响", "E": "增加上下文窗口长度可以完全解决迷失在中间问题"}', 'ABD', 'C错误：LLM没有跨会话记忆，每次对话从零开始；E错误：更大的上下文窗口不能解决注意力分布不均（迷失在中间依然存在）。', NULL, 3, NULL, 'null', NULL, NULL, NULL, 'draft', 0, NULL, NULL, NULL, NULL, 'f153e781-dca0-46af-8430-a62aa9b59a9b', NULL, '2026-04-14 02:29:56.371185+00', '2026-04-14 02:29:56.371189+00');
INSERT INTO public.questions VALUES ('c3cd3585-72a9-4c59-a76b-66cff1526a1a', 'multiple_choice', '关于AI生成内容的版权与伦理，以下哪些说法是正确的？（多选）', '{"A": "目前全球大多数司法管辖区不承认纯AI生成内容享有著作权", "B": "使用AI工具辅助写作的论文，其版权归AI工具的开发者所有", "C": "AI在生成内容时可能无意中复现训练数据中受版权保护的文本片段", "D": "各学术机构对AI在论文写作中的使用规范尚无统一标准，各机构规定不同", "E": "只要最终经人类修改过，AI生成的内容就完全不存在版权或诚信问题"}', 'ACD', 'B错误：版权通常归使用AI的人类创作者，不归AI开发商；E错误：过度依赖或不标注AI使用仍可能违反学术诚信规定。', NULL, 3, NULL, 'null', NULL, NULL, NULL, 'draft', 0, NULL, NULL, NULL, NULL, 'f153e781-dca0-46af-8430-a62aa9b59a9b', NULL, '2026-04-14 02:29:56.374622+00', '2026-04-14 02:29:56.374625+00');
INSERT INTO public.questions VALUES ('a151c0ec-b419-495b-95e2-e890ae913d31', 'true_false', 'AI在同一次对话中纠正了错误后，会将这种学习保留到下一次独立对话，从而避免犯同样的错误。（　　）', '{"F": "错误", "T": "正确"}', 'F', 'LLM没有跨会话记忆机制，每次对话都是独立的；同一次对话中AI可能临时调整，但这不是真正的学习，下次对话不会保留。', NULL, 3, NULL, 'null', NULL, NULL, NULL, 'draft', 0, NULL, NULL, NULL, NULL, 'f153e781-dca0-46af-8430-a62aa9b59a9b', NULL, '2026-04-14 02:31:25.955269+00', '2026-04-14 02:31:25.955274+00');
INSERT INTO public.questions VALUES ('fdfdb0a1-4b82-45f5-815f-99e7f18ecd69', 'true_false', '如果AI引用了一位真实存在的学者的名字，那么它关于这位学者的其他信息（如论文标题、发表年份）也很可能是准确的。（　　）', '{"F": "错误", "T": "正确"}', 'F', '真实姓名加虚构细节是AI幻觉的典型模式：AI会在真实人名周围生成听起来合理但可能完全错误的信息（如虚构的论文标题）。', NULL, 3, NULL, 'null', NULL, NULL, NULL, 'draft', 0, NULL, NULL, NULL, NULL, 'f153e781-dca0-46af-8430-a62aa9b59a9b', NULL, '2026-04-14 02:31:25.964228+00', '2026-04-14 02:31:25.964234+00');
INSERT INTO public.questions VALUES ('a0f17a5c-1447-41a4-9600-54bab3c2d3aa', 'true_false', '用多个不同AI工具（如GPT-4、Claude、文心一言）对同一问题交叉验证，如果都给出相同答案，则该答案的可信度更高。（　　）', '{"F": "错误", "T": "正确"}', 'F', '多个主流模型共享大量重叠的训练数据，若某错误信息在网络上广泛流传，多个模型可能学习了同一错误并给出一致的错误答案——这是共同错误偏差。', NULL, 3, NULL, 'null', NULL, NULL, NULL, 'draft', 0, NULL, NULL, NULL, NULL, 'f153e781-dca0-46af-8430-a62aa9b59a9b', NULL, '2026-04-14 02:31:25.968369+00', '2026-04-14 02:31:25.968377+00');
INSERT INTO public.questions VALUES ('479f275d-79fd-436b-84c1-7c5ec864462a', 'true_false', 'AI在回答中表达不确定性（如【我可能有误】），说明该信息的可信度低于AI直接自信作答时。（　　）', '{"F": "错误", "T": "正确"}', 'F', '能表达不确定性是AI对齐训练的积极成果；过度自信的AI实际上风险更高，适当表达不确定性反而是较好的校准（Calibration）表现。', NULL, 3, NULL, 'null', NULL, NULL, NULL, 'draft', 0, NULL, NULL, NULL, NULL, 'f153e781-dca0-46af-8430-a62aa9b59a9b', NULL, '2026-04-14 02:31:25.972473+00', '2026-04-14 02:31:25.97248+00');
INSERT INTO public.questions VALUES ('d6c42543-cbad-45b7-8833-f4962ff34ee7', 'true_false', 'AI在接受用户的纠正或反驳后给出的新答案，不一定比原来的答案更正确——AI可能只是在迎合用户。（　　）', '{"F": "错误", "T": "正确"}', 'T', '这正是AI顺从性偏见（Sycophancy）的表现：AI倾向于迎合用户的纠正，即使用户的纠正本身是错误的。', NULL, 3, NULL, 'null', NULL, NULL, NULL, 'draft', 0, NULL, NULL, NULL, NULL, 'f153e781-dca0-46af-8430-a62aa9b59a9b', NULL, '2026-04-14 02:31:25.976331+00', '2026-04-14 02:31:25.976336+00');
INSERT INTO public.questions VALUES ('45c9fb40-533f-4539-8b2d-1386f2c90bd6', 'true_false', '【开源】大语言模型意味着任何人都可以免费将其用于任何商业目的。（　　）', '{"F": "错误", "T": "正确"}', 'F', '开源模型的许可证各不相同，许多有商业使用限制；开源不等于完全自由商用，需仔细查阅具体许可协议。', NULL, 3, NULL, 'null', NULL, NULL, NULL, 'draft', 0, NULL, NULL, NULL, NULL, 'f153e781-dca0-46af-8430-a62aa9b59a9b', NULL, '2026-04-14 02:31:25.980331+00', '2026-04-14 02:31:25.980335+00');
INSERT INTO public.questions VALUES ('c230a42d-430d-415b-bd51-44f60c63d710', 'true_false', '大语言模型在处理需要精确数字计算的任务时，可靠性通常高于其在事实陈述任务上的可靠性。（　　）', '{"F": "错误", "T": "正确"}', 'F', 'LLM在精确数学计算上表现相当不可靠，这是其众所周知的弱点；相比之下，语言相关任务（如改写、摘要）通常更为稳定。', NULL, 3, NULL, 'null', NULL, NULL, NULL, 'draft', 0, NULL, NULL, NULL, NULL, 'f153e781-dca0-46af-8430-a62aa9b59a9b', NULL, '2026-04-14 02:31:25.984004+00', '2026-04-14 02:31:25.984007+00');
INSERT INTO public.questions VALUES ('00f76091-f0db-492b-8cdf-e5c373b26abe', 'true_false', '在提示词中给AI设定一个专业角色（如【你是一位资深图书馆研究专家】），可以确保AI给出的内容具有该领域专家水准。（　　）', '{"F": "错误", "T": "正确"}', 'F', '角色设定可以调整输出风格和结构，但无法赋予AI实际上不具备的专业知识；AI依然会在该角色下产生幻觉。', NULL, 3, NULL, 'null', NULL, NULL, NULL, 'draft', 0, NULL, NULL, NULL, NULL, 'f153e781-dca0-46af-8430-a62aa9b59a9b', NULL, '2026-04-14 02:31:25.988003+00', '2026-04-14 02:31:25.988007+00');
INSERT INTO public.questions VALUES ('f4005d63-5402-4827-a56d-0ccb871b7e5e', 'true_false', 'AI拒绝回答某个问题，意味着该问题在道德上或内容上存在问题。（　　）', '{"F": "错误", "T": "正确"}', 'F', 'AI的拒答可能是过度谨慎的误判（假阳性）：完全无害的问题有时也会触发安全过滤机制，拒答并不等于问题本身有道德问题。', NULL, 3, NULL, 'null', NULL, NULL, NULL, 'draft', 0, NULL, NULL, NULL, NULL, 'f153e781-dca0-46af-8430-a62aa9b59a9b', NULL, '2026-04-14 02:31:25.991201+00', '2026-04-14 02:31:25.991205+00');
INSERT INTO public.questions VALUES ('d910da84-f99e-4156-bf08-30580b6b32c0', 'single_choice', '你告诉AI它之前说X是错的，应该是Y，但实际上X才是正确答案。AI最可能的反应是（　　）：', '{"A": "坚持原来正确的答案X，并提供支持证据", "B": "修正为Y并道歉，即使Y是错误的——这反映了AI的顺从性偏见（Sycophancy）", "C": "要求你先提供证据再修改答案", "D": "同时呈现X和Y，让用户自行判断"}', 'B', '顺从性偏见（Sycophancy）是LLM的已知缺陷：AI倾向于迎合用户表达的观点，即使这意味着放弃正确答案，这是对齐训练的意外副产品。', NULL, 3, NULL, 'null', NULL, NULL, NULL, 'draft', 0, NULL, NULL, NULL, NULL, 'f153e781-dca0-46af-8430-a62aa9b59a9b', NULL, '2026-04-14 02:31:25.996964+00', '2026-04-14 02:31:25.996969+00');
INSERT INTO public.questions VALUES ('1a23ba47-c200-4448-82c7-0c25f68a413f', 'single_choice', '一位研究生让AI用客观中立的立场分析某一政治议题。以下哪个风险最需要警惕？（　　）', '{"A": "AI会因此直接拒绝回答", "B": "AI所谓的中立立场实际上反映了训练数据中的主导性话语框架，并非真正的价值无涉", "C": "AI会随机选择一种立场", "D": "只有非中文模型才存在这个问题"}', 'B', 'AI的训练数据本身代表了特定的话语权力结构，所谓中立不过是将主流框架自然化；研究者需对AI的立场预设保持批判意识。', NULL, 3, NULL, 'null', NULL, NULL, NULL, 'draft', 0, NULL, NULL, NULL, NULL, 'f153e781-dca0-46af-8430-a62aa9b59a9b', NULL, '2026-04-14 02:31:26.00047+00', '2026-04-14 02:31:26.000476+00');
INSERT INTO public.questions VALUES ('00160cb8-77f7-419c-840b-1b650fbba8d3', 'single_choice', '某研究者今天问AI某理论的提出者是谁，得到答案A；明天问同样的问题，得到了不同的答案B。最可能的原因是（　　）：', '{"A": "AI在夜间自动更新了知识库", "B": "两次提问的措辞一定存在差异", "C": "温度参数大于0时，LLM的输出具有随机性，相同问题可能产生不同答案", "D": "AI检测到用户身份不同，故意给出不同答案"}', 'C', 'LLM的随机采样机制（温度>0）意味着相同输入并不保证相同输出，同一问题在不同时间得到不同答案是正常现象。', NULL, 3, NULL, 'null', NULL, NULL, NULL, 'draft', 0, NULL, NULL, NULL, NULL, 'f153e781-dca0-46af-8430-a62aa9b59a9b', NULL, '2026-04-14 02:31:26.004401+00', '2026-04-14 02:31:26.004405+00');
INSERT INTO public.questions VALUES ('edd64eef-0cda-489f-ad39-46d75a1d4018', 'single_choice', '某研究者用AI对100份问卷的开放性回答进行情感分析，发现AI将若干份标注为中性，但人工复核后确认这些回答都表达了隐晦的负面情绪。这反映了AI的什么局限性？（　　）', '{"A": "AI无法同时处理100份以上的问卷", "B": "问卷设计本身存在缺陷", "C": "AI对讽刺、隐喻、文化特定情感表达方式的理解能力有限", "D": "研究者应改用英文问卷"}', 'C', '隐晦表达、反讽、文化特异性情感是LLM情感分析的主要弱点，AI在识别非直白情感表达时准确率显著下降。', NULL, 3, NULL, 'null', NULL, NULL, NULL, 'draft', 0, NULL, NULL, NULL, NULL, 'f153e781-dca0-46af-8430-a62aa9b59a9b', NULL, '2026-04-14 02:31:26.00811+00', '2026-04-14 02:31:26.008115+00');
INSERT INTO public.questions VALUES ('378d068d-eda1-46e1-accd-9a3ba7cf79e3', 'single_choice', '以下哪种提示词设计最可能导致AI产生确认偏误（Confirmation Bias）式的回答？（　　）', '{"A": "请分析X理论的优点和缺点", "B": "请帮我找出支持X观点的所有论据，越多越好", "C": "请以批判性视角评价X理论的局限性", "D": "X理论存在哪些已被学界证伪的论断？"}', 'B', '要求AI只找支持性论据是人为制造确认偏误，AI会忽略反例，产生片面强化预设观点的输出。', NULL, 3, NULL, 'null', NULL, NULL, NULL, 'draft', 0, NULL, NULL, NULL, NULL, 'f153e781-dca0-46af-8430-a62aa9b59a9b', NULL, '2026-04-14 02:31:26.012044+00', '2026-04-14 02:31:26.012048+00');
INSERT INTO public.questions VALUES ('555cb852-cb69-4197-a078-d7a251d8d744', 'single_choice', '以下哪种对大语言模型上下文窗口的理解是错误的？（　　）', '{"A": "上下文窗口是指模型在单次对话中能处理的最大文本长度", "B": "超出上下文窗口的内容会被模型直接截断或遗忘", "C": "上下文窗口越大，模型对窗口内所有信息的关注程度就越均匀", "D": "不同模型的上下文窗口大小各不相同"}', 'C', '这是迷失在中间（Lost-in-the-Middle）问题的根源：即使文本在窗口内，LLM对中间位置的注意力也系统性低于首尾——窗口大小与注意力均匀性无关。', NULL, 3, NULL, 'null', NULL, NULL, NULL, 'draft', 0, NULL, NULL, NULL, NULL, 'f153e781-dca0-46af-8430-a62aa9b59a9b', NULL, '2026-04-14 02:31:26.015878+00', '2026-04-14 02:31:26.015884+00');
INSERT INTO public.questions VALUES ('fd0b146a-cb9f-4f7f-90c2-31350eff0d5c', 'single_choice', '在以下哪种情况下，使用AI生成摘要的幻觉风险最高？（　　）', '{"A": "对一篇已完整提供给AI的中文新闻报道进行摘要", "B": "对一篇已完整提供给AI的英文学术论文进行摘要", "C": "对一位你口头描述过但未提供任何原文的学者的研究进行摘要", "D": "对一段已提供全文的历史演讲词进行摘要"}', 'C', '未提供原文时，AI没有任何可参考的内容，会凭空生成关于该学者研究的叙述，是幻觉风险最高的场景。', NULL, 3, NULL, 'null', NULL, NULL, NULL, 'draft', 0, NULL, NULL, NULL, NULL, 'f153e781-dca0-46af-8430-a62aa9b59a9b', NULL, '2026-04-14 02:31:26.019511+00', '2026-04-14 02:31:26.019516+00');
INSERT INTO public.questions VALUES ('94a4716f-b4ec-4050-a04e-106e51b7f922', 'single_choice', '某学者认为AI在人文社科研究中毫无用处，因为AI不能真正理解人类情感和文化。对这一观点最合理的评价是（　　）：', '{"A": "完全正确，缺乏主观体验的AI无法用于任何人文研究", "B": "完全错误，AI已完全理解了人类情感", "C": "部分合理：AI对情感和文化的处理存在局限，但不妨碍AI在辅助文本处理、模式识别等具体任务上发挥价值", "D": "只要模型足够大，就能完全理解人类情感"}', 'C', '这是最均衡的判断：承认AI的局限性，但也承认其在特定任务上的工具价值，避免了全盘否定和全盘接受两个极端。', NULL, 3, NULL, 'null', NULL, NULL, NULL, 'draft', 0, NULL, NULL, NULL, NULL, 'f153e781-dca0-46af-8430-a62aa9b59a9b', NULL, '2026-04-14 02:31:26.023562+00', '2026-04-14 02:31:26.023569+00');
INSERT INTO public.questions VALUES ('e44c107c-f350-44a0-9815-b938a3fced6c', 'single_choice', '以下哪个场景中，AI的回答最可能受到训练数据偏差的影响，而非单纯的事实错误？（　　）', '{"A": "AI计算3×7等于多少", "B": "AI描述某国内战的历史起因（该国在英文主流媒体中报道较少）", "C": "AI将一首现代中文诗歌翻译成英文", "D": "AI将一篇文章改写成简洁版本"}', 'B', '低资源报道语境中AI的描述更多反映了训练数据中的叙事框架偏差，这是系统性偏差而非随机错误。', NULL, 3, NULL, 'null', NULL, NULL, NULL, 'draft', 0, NULL, NULL, NULL, NULL, 'f153e781-dca0-46af-8430-a62aa9b59a9b', NULL, '2026-04-14 02:31:26.028248+00', '2026-04-14 02:31:26.028252+00');
INSERT INTO public.questions VALUES ('f38b30c4-31c9-4d8d-88b9-38a49aecf740', 'single_choice', '以下哪种情形最能说明AI存在幻觉问题，而非普通的知识缺失？（　　）', '{"A": "AI表示不知道某件事，无法作答", "B": "AI正确指出自己的训练数据可能不包含该信息", "C": "AI编造了一篇完整的不存在的论文，包括逼真的作者名、期刊名、卷期和页码", "D": "AI给出的答案与另一份权威资料略有出入"}', 'C', '幻觉的典型特征是自信地生成虚假但形式完整的内容；A和B是合理的不确定性表达，D是知识分歧，只有C符合幻觉的定义。', NULL, 3, NULL, 'null', NULL, NULL, NULL, 'draft', 0, NULL, NULL, NULL, NULL, 'f153e781-dca0-46af-8430-a62aa9b59a9b', NULL, '2026-04-14 02:31:26.033053+00', '2026-04-14 02:31:26.033058+00');
INSERT INTO public.questions VALUES ('370f2d12-aa38-4cde-929e-06cd50b3b171', 'multiple_choice', '以下哪些属于AI幻觉的典型表现形式？（多选）', '{"A": "AI引用了一篇格式完整但实际并不存在的学术文献", "B": "AI表示自己对某问题不确定，可能有误", "C": "AI对某位真实学者的研究方向做出了部分错误的描述", "D": "AI生成了一段文笔流畅但含有错误史实的历史叙述", "E": "AI以极高置信度将某位学者的成果归功于另一位真实存在的学者"}', 'ACDE', 'B是AI合理表达不确定性，属于正常的校准行为而非幻觉；A、C、D、E均为AI自信生成虚假或错误内容的典型形式。', NULL, 3, NULL, 'null', NULL, NULL, NULL, 'draft', 0, NULL, NULL, NULL, NULL, 'f153e781-dca0-46af-8430-a62aa9b59a9b', NULL, '2026-04-14 02:31:26.039013+00', '2026-04-14 02:31:26.039017+00');
INSERT INTO public.questions VALUES ('12391aa9-583f-4f1f-ac77-887cf5ff61e2', 'multiple_choice', '以下哪些做法有助于降低在学术研究中使用AI工具的风险？（多选）', '{"A": "对AI提供的每一条具体事实和文献引用进行独立核实", "B": "优先使用参数量超过1000亿的大型模型，以减少错误", "C": "在采纳AI输出前，保持批判性审视而非被动接受", "D": "明确了解所用AI工具的知识截止日期和数据来源局限性", "E": "将AI输出全部改为第三人称以降低可识别性"}', 'ACD', 'B错误：参数量不是衡量准确性的可靠指标；E与降低风险无关，是表面规避而非实质性核实。A、C、D是切实有效的风险管理措施。', NULL, 3, NULL, 'null', NULL, NULL, NULL, 'draft', 0, NULL, NULL, NULL, NULL, 'f153e781-dca0-46af-8430-a62aa9b59a9b', NULL, '2026-04-14 02:31:26.043275+00', '2026-04-14 02:31:26.043281+00');
INSERT INTO public.questions VALUES ('39335dd5-7af4-459a-a40f-37213bf0ba94', 'multiple_choice', '以下关于AI在质性研究中的应用，哪些说法是正确的？（多选）', '{"A": "AI可以辅助研究者对大批量文本进行初步编码，提高处理效率", "B": "AI辅助编码结果应视为最终结论，无需人工复核", "C": "在研究报告中应说明AI工具的使用方式及人工审核过程", "D": "AI可能遗漏具有文化特殊性的表达，研究者需特别关注", "E": "AI处理质性数据比人类更客观，因此编码结果更具科学性"}', 'ACD', 'B错误：AI辅助编码仍需人工审核，不能视为最终结论；E错误：AI在质性编码中并非更客观，其文化偏差可能更深层且难以发现。', NULL, 3, NULL, 'null', NULL, NULL, NULL, 'draft', 0, NULL, NULL, NULL, NULL, 'f153e781-dca0-46af-8430-a62aa9b59a9b', NULL, '2026-04-14 02:31:26.048286+00', '2026-04-14 02:31:26.048293+00');
INSERT INTO public.questions VALUES ('580a98a6-8c88-4dd5-a76a-648ef088caac', 'multiple_choice', '以下哪些因素可能导致不同AI工具对同一问题给出相似的错误答案？（多选）', '{"A": "多个主流AI模型的训练数据中存在大量重叠的网络文本来源", "B": "AI模型之间存在协议，确保彼此答案保持一致", "C": "某些错误信息在互联网上广泛传播，被多个模型反复学习内化", "D": "所有主流AI模型均由同一家公司开发", "E": "网络上关于某些话题的信息本身存在系统性偏差，多个模型都从中学习了同样的偏差"}', 'ACE', 'B错误：AI模型之间不存在协议；D错误：主流AI由多家公司开发（OpenAI、Anthropic、百度、Google等）；A、C、E解释了共同错误偏差的真实成因。', NULL, 3, NULL, 'null', NULL, NULL, NULL, 'draft', 0, NULL, NULL, NULL, NULL, 'f153e781-dca0-46af-8430-a62aa9b59a9b', NULL, '2026-04-14 02:31:26.052985+00', '2026-04-14 02:31:26.05299+00');
INSERT INTO public.questions VALUES ('b267b969-e69f-4ae0-8b1f-22dc2ed95f14', 'multiple_choice', '关于AI工具在人文社科领域的应用边界，以下哪些判断较为合理？（多选）', '{"A": "AI可以高效辅助文本格式转换、初步分类和语言润色等任务", "B": "涉及价值判断、伦理权衡和深度文化解读的核心研究工作，不应完全外包给AI", "C": "AI目前已能完全替代人类进行批判性分析和文化解读", "D": "理解AI的局限性本身，已成为数字时代人文社科研究能力的重要组成部分", "E": "AI在处理低资源语言（训练数据较少的语言）的文本时，表现通常不如处理英文文本"}', 'ABDE', 'C错误：AI目前尚无法完全替代人类进行深度批判性分析；A、B、D、E均为对AI能力边界较为准确的专业判断。', NULL, 3, NULL, 'null', NULL, NULL, NULL, 'draft', 0, NULL, NULL, NULL, NULL, 'f153e781-dca0-46af-8430-a62aa9b59a9b', NULL, '2026-04-14 02:31:26.058229+00', '2026-04-14 02:31:26.058235+00');
